# Align posterior draws
n_draw <- min(nrow(post_mi), nrow(post_d))
post_mi <- post_mi[1:n_draw, ]
post_d  <- post_d[1:n_draw, ]

# -------------------------------------------------
# Probability of spontaneous MI by treatment arm
# (logit link → inverse-logit)
# -------------------------------------------------
p_mi_cabg <- plogis(post_mi$b_Intercept)
p_mi_pci  <- plogis(post_mi$b_Intercept + post_mi$b_armPCI)

# -------------------------------------------------
# Probability of death conditional on spontaneous MI
# (entered as percentages → convert to probabilities)
# no need for plogis since gaussian model is already on probability scale
# -------------------------------------------------
p_d_cabg <- post_d$b_Intercept / 100
p_d_pci  <- (post_d$b_Intercept + post_d$b_armPCI) / 100

# -------------------------------------------------
# Truncate probabilities to [0,1] due to linear model simpler than alternative
# Replace gaussian with logit‑normal likelihood 
# brm(yi | se(sei) ~ arm,family = gaussian(link = "logit"))
# Then need to apply inverse logit
# -------------------------------------------------
p_d_cabg <- pmin(pmax(p_d_cabg, 0), 1)
p_d_pci  <- pmin(pmax(p_d_pci,  0), 1)

# -------------------------------------------------
# Overall risk of death MI‑associated mortality risk
# -------------------------------------------------
risk_cabg <- p_mi_cabg * p_d_cabg
risk_pci  <- p_mi_pci  * p_d_pci


ci_risk_cabg <- quantile(risk_cabg, c(0.025, .50, 0.975))
ci_risk_pci <- quantile(risk_pci, c(0.025, .50, 0.975))

diff_overall <- risk_pci - risk_cabg

p_combined <- mean(diff_overall > 0)

ci_diff_overall <- quantile(diff_overall, c(0.025, 0.5, 0.975))
