### Posterior plot for the combined two‑model estimand



::: {.cell layout-align="center"}

```{.r .cell-code}
library(ggplot2)

# Posterior probability (define explicitly)
p_combined <- mean(diff_overall > 0)

plot_df <- data.frame(diff = diff_overall)

# Compute ONE normalized density via ggplot
density_data <- ggplot_build( ggplot(plot_df, aes(x = diff)) +
    geom_density())$data[[1]]

ggplot() +
  # Full posterior density
  geom_line(
    data = density_data,
    aes(x = x, y = density),
    linewidth = 1
  ) +
  # Area where diff <= 0
  geom_area(
    data = subset(density_data, x <= 0),
    aes(x = x, y = density),
    fill = "lightblue",
    alpha = 0.6
  ) +
  # Area where diff > 0 (AUC = posterior probability)
  geom_area(
    data = subset(density_data, x > 0),
    aes(x = x, y = density),
    fill = "red",
    alpha = 0.6
  ) +
  geom_vline(xintercept = 0, linetype = "dashed") +
  annotate(
  "text",
  x = Inf, y = Inf,
  label = sprintf("P(PCI > CABG) == %.2f", p_combined),
  parse = TRUE,
  hjust = 1.1,
  vjust = 1.4,
  color = "red",
  size = 5
) +
  labs(
    title = "Posterior Distribution of Post MI Mortality Difference",
    subtitle = "Difference = PCI − CABG",
    x = "Difference in post MI death probability",
    y = "Posterior density"
  ) +
  theme_minimal()
```

